<template>
	<view class="content-box">
		<view class="tabs">
			<uni-segmented-control :current="current" :values="items"
			 @clickItem="onClickItem" />
		 </view>
		<uni-card @click="edit(item._id)" :sub-title="item.top?'ч╜ощб╢':item.is_today_important==='1'?'ф╗КцЧехЕ│ц│и':''" :class="[item.is_today_important==='1'?'today':'']" v-for="item in list" :key="item._id" :title="item.title"  :extra="item.type" >
		
			<view class="content"  v-if="item.content">
				<view class="uni-body" user-select v-html="item.content"></view>
			</view>
			<view class="imgs" v-if="item.imgs">
				<image @click="preImg(item.imgs,index)" v-for="(img,index) in item.imgs.split(';')" class="img" :src="img" mode="aspectFill"></image>
			</view>
			<view class="uni-body bz" v-html="item.bz"></view>
			<uni-link :href="item.url" :text="item.url"></uni-link>
			<view slot="actions" class="card-actions" v-if="item.type==='task'">
				<view class="card-actions-item" @click="addTask(item)">
					<uni-icons type="heart" size="18" color="pink"></uni-icons>
					<text class="card-actions-item-text">ц╖╗хКахИ░цИСчЪДф╗╗хКб</text>
				</view>
			</view>
		
		</uni-card>
		<view v-if="!list.length&&!loading" class="tips">цЪВцЧацХ░цНо</view>
		<view class="edit" @click="edit()" v-if="userInfo._id==='68b547748a5c782a2b48ac30'">+</view>
		
	</view>
</template>

<script>

	export default {
		data() {
			return {
				list:[],
				url:'',
				items: ['щАЪчЯехЕмхСК', 'хнШч╗нхХЖхКб','хЬи/х╛ЕцТнф╜ЬхУБ','ц╝ФхЗ║/ц┤╗хКи'],
				current: 0,
				loading:false,
				userInfo:{
					_id:''
				}
			}
		},
		onShareAppMessage: function () {
		   return {
		     title: 'хоЗщЭТщЭТхоЗхЕишВпхоЪ',
		     path: '/pages/rili/rili'
		   }
		 },
		 onShareTimeline: function () {
		    return {
		      title: 'хоЗщЭТщЭТхоЗхЕишВпхоЪ'
		    }
		  },
		  onLoad() {
		  	this.get()
			try {
				const userInfo = uni.getStorageSync('userInfo');
				this.userInfo=JSON.parse(userInfo)
			} catch (e) {
				// error
			}
		  },
		  onPullDownRefresh() {
		  	this.get()
		  },
		methods: {
			edit(id){
				if(this.userInfo._id!=='68b547748a5c782a2b48ac30') return
				id=id||''
				uni.navigateTo({
					url:`/pages/edit/notice?id=${id}`
				});
			},
			onClickItem(e){
				if (this.current !== e.currentIndex) {
					this.current = e.currentIndex
					this.get()
				}
			},
			
			get() {
				uni.showLoading({
					title: 'хдДчРЖф╕н...'
				})
				this.loading=true
				uniCloud.callFunction({
					name: 'notice',
					data:{
						type:'get',
						classType:this.current.toString()
					}
				}).then((res) => {
					uni.hideLoading()
					uni.stopPullDownRefresh();
					this.list=res.result.data
					this.loading=false
				}).catch((err) => {
					uni.hideLoading()
					uni.stopPullDownRefresh();
					uni.showModal({
						content: `цЯешпвхд▒ш┤ея╝МщФЩшппф┐бцБпф╕║я╝Ъ${err.message}`,
						showCancel: false
					})
					this.loading=false
				})
			},
			lower(){
				alert(1)
			},
			 addTask(item){
				uni.showLoading({
					title: 'хдДчРЖф╕н...'
				})
				try {
					const user = uni.getStorageSync('userInfo');
					console.log('user',user)
					if(!user){
						uni.hideLoading()
						uni.showModal({
							content: `ш┐ШцЬкчЩ╗х╜Хшп╖хЕИхО╗чЩ╗х╜Х`,
							showCancel: false
						})
						return
					}
					let userInfo=JSON.parse(user)
					uniCloud.callFunction({
						name: 'user-todo',
						data: {
							type: 'add',
							userID: userInfo._id,
							title:item.title,
							taskID:item._id
						}
					}).then((res) => {
						console.log('res',res)
						uni.hideLoading()
						if(res.result.code){
							uni.showModal({
								content: `${res.result.message}`,
								showCancel: false
							})
						}else{
							uni.showModal({
								content: `цИРхКЯц╖╗хКаф╕║цИСчЪДф╗╗хКбя╝МхПпф╗ехО╗цИСчЪДtodoщЗМцЯечЬЛ`,
								showCancel: false
							})
						}
						
					}).catch((err) => {
						uni.hideLoading()
						uni.showModal({
							content: `ц╖╗хКацХ░цНохд▒ш┤ея╝МщФЩшппф┐бцБпф╕║я╝Ъ${err.message}`,
							showCancel: false
						})
						console.error(err)
					})
				} catch (e) {
					uni.hideLoading()
					uni.showModal({
						content: `ш┐ШцЬкчЩ╗х╜Хшп╖хЕИхО╗чЩ╗х╜Х`,
						showCancel: false
					})
				}
				
			},
			actionsClick(url){
				this.url=url
			},
			preImg(imgs,i){
				// щвДшзИхЫ╛чЙЗ
				const urls=imgs.split(';')||[]
						uni.previewImage({
							urls ,
							current :i,
							longPressActions: {
								itemList: ['хПСщАБч╗ЩцЬЛхПЛ', 'ф┐ЭхнШхЫ╛чЙЗ', 'цФ╢шЧП'],
								success: function(data) {
									console.log('щАЙф╕нф║Жчмм' + (data.tapIndex + 1) + 'ф╕кцМЙщТо,чмм' + (data.index + 1) + 'х╝ахЫ╛чЙЗ');
								},
								fail: function(err) {
									console.log(err.errMsg);
								}
							}
						});
			}
		}
	}
</script>

<style lang="scss">
.content-box {
	padding: 30px 0 10px;
	background: linear-gradient(180deg, #c4aff3 0%, #cdf8f5 100%);
	min-height: 100vh;
}
	.card-actions {
			display: flex;
			flex-direction: row;
			justify-content: space-around;
			align-items: center;
			height: 45px;
			border-top: 1px #eee solid;
		}
		
		.card-actions-item {
			display: flex;
			flex-direction: row;
			align-items: center;
		}
		.card-actions-item-text {
			font-size: 12px;
			color: #140929;
			margin-left: 5px;
		}

	.content {
		border-bottom:1px solid #ccc;
		padding-bottom:10px ;
		color: #010a09;
	}
	.bz{
		color: #f7b606;
		padding: 5px 0;
	}
	.title {
		font-weight: bold;
		align-items: center;
		padding: 20px 0px;
		font-size: 20px;
	}

	.tips {
		color: #fff;
		font-size: 14px;
		padding: 20px 30px;
	}

	.btn-list {
		padding: 0px 30px;
	}

	.btn-list button {
		margin-bottom: 20px;
	}

	.upload-preview {
		width: 100%;
	}

	#tip {
		width: 750rpx;
		align-items: center;
	}
	.imgs{
		display: flex;
		flex-wrap: wrap;
		.img{
			width: 60px;height: 60px;margin: 10px;
		}
	}
	.uni-card {
		background: linear-gradient(135deg,#fff,#baf5f1,#d6ccfa )!important;
		border:0!important;
		border-radius: 18px!important;
	}
	.uni-card__header-extra-text{
		color: #fff!important;
	}
	.uni-card .uni-card__header .uni-card__header-content .uni-card__header-content-subtitle {
		width:50px;text-align:center;background: #a9a9d9;color: #180e24!important;border-radius: 2px;padding: 2px;
	}
	.today{
		.uni-card .uni-card__header .uni-card__header-content .uni-card__header-content-subtitle{
			background: #31eee0;
			color: #0e2424!important;
		}
	}
	.tabs{
		padding: 0 10px;
		position: fixed;
		top:5px;
		left: 0;
		width: 100%;
		z-index: 99;
		
	}
	.segmented-control {
		.segmented-control__text{
			color: #3f2649!important;
		}
		.segmented-control__item {
			background: #c4aff3;
			border-color:#f7f7f7!important;
		}
		.segmented-control__item--button--active{
			background: linear-gradient(to top,#baf5f1,#d6ccfa )!important;
		}
		.segmented-control__item--button--first{
			border-top-left-radius: 18px!important;
			border-bottom-left-radius: 18px!important;
		}
		.segmented-control__item--button--last{
			border-top-right-radius: 18px!important;
			border-bottom-right-radius: 18px!important;
		}
	}
	
	.tips{
		text-align: center;
		color: #fff;
		padding: 20px;
	}
	.edit{
		position: fixed;
		right: 5px;bottom: 30px;border-radius: 100%;width: 38px;height: 38px;background: #aaffff;color: #926eff;font-size: 12px;line-height: 38px;text-align: center;box-shadow: 0 0 13px 5px rgba(0,0,0,.1);
	}
</style>
